265→    snippetForm,
266→    showToast,
267→    handleDrillBack,
268→  ]);
269→
270→  const handleGridAction = useCallback(
271→    (index: number) => {
272→      const color = filteredColors[index];
273→      if (color) {
274→        showToast({
275→          style: 'info',
276→          title: 'Copied color',
